CREATE TABLE t_p60960229_website_stats_dashbo.sites (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, url VARCHAR(500) NOT NULL, description TEXT, screenshot_url TEXT, category_id INTEGER, status VARCHAR(20) DEFAULT 'pending', verified BOOLEAN DEFAULT FALSE, rating NUMERIC(3,2) DEFAULT 0, total_visits BIGINT DEFAULT 0, total_views BIGINT DEFAULT 0, owner_email VARCHAR(255), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())